const { whisper } = require('whisper-node');
const fs = require('fs');

// 设置模型路径
process.env.WHISPER_MODEL_PATH = "/tmp/whisper-models/ggml-tiny.bin";

async function main() {
    console.log("🚀 开始语音识别...\n");
    try {
        const options = {
            modelName: "tiny",
            modelPath: "/tmp/whisper-models/ggml-tiny.bin",
            whisperPath: "/tmp/node_modules/whisper-node/lib/whisper.cpp/main"
        };

        const transcript = await whisper("/tmp/bilibili_audio.wav", options);

        console.log("📝 逐句识别结果:\n");
        if (Array.isArray(transcript)) {
            transcript.forEach((t, i) => {
                console.log(`  [${t.start} → ${t.end}] ${t.speech}`);
            });

            const fullText = transcript.map(t => t.speech).join(" ");
            console.log("\n📄 全文:\n");
            console.log(fullText);

            fs.writeFileSync("/tmp/transcript.json", JSON.stringify(transcript, null, 2));
            fs.writeFileSync("/tmp/transcript.txt", fullText);
            console.log("\n✅ 已保存到 /tmp/transcript.txt 和 transcript.json");
        } else {
            console.log(JSON.stringify(transcript, null, 2));
        }
    } catch(e) {
        console.error("❌ 错误:", e.message);
        console.error(e.stack);
    }
}

main();

